/* Aula 25 — modelJs: timers, debounce, contador */

const busca = document.querySelector('#busca');
const status = document.querySelector('#status');
const start = document.querySelector('#start');
const stop = document.querySelector('#stop');
const contadorEl = document.querySelector('#contador');

let debounceId = null;
let intervalId = null;
let count = 0;

if (busca && status) {
  busca.addEventListener('input', () => {
    status.textContent = 'digitando...';

    // debounce: cancela o anterior
    if (debounceId) clearTimeout(debounceId);

    debounceId = setTimeout(() => {
      status.textContent = 'parou';
      debounceId = null;
    }, 800);
  });
}

function iniciarContador() {
  if (intervalId) return; // proteção: não cria 2
  count = 0;
  if (contadorEl) contadorEl.textContent = String(count);

  intervalId = setInterval(() => {
    count++;
    if (contadorEl) contadorEl.textContent = String(count);
  }, 1000);
}

function pararContador() {
  if (!intervalId) return;
  clearInterval(intervalId);
  intervalId = null;
}

if (start) start.addEventListener('click', iniciarContador);
if (stop) stop.addEventListener('click', pararContador);
